description:
Why: The library has message_create but no way to edit body, manage reactions, mark read, delete, or destroy messages. These are required for a complete chat experience.

What: Add to mod.rs: ReactionChange<'a> enum and MessageUpdateInput<'a> struct. Add to message.rs: message_set_update() and message_set_destroy() methods.

Algorithm:

Step 1 — Add types to crates/jmap-chat/src/methods/mod.rs, after the MessageCreateInput block:

/// One reaction change in a Message/set patch (JMAP Chat §4.5).
///
/// The patch key is "reactions/<senderReactionId>" (JSON Pointer).
/// senderReactionId is a caller-generated ID (ULID) unique per reaction.
#[derive(Debug)]
pub enum ReactionChange<'a> {
    /// Add a reaction. Patch value: {emoji, sentAt}.
    Add {
        sender_reaction_id: &'a str,
        emoji: &'a str,
        sent_at: &'a crate::jmap::UTCDate,
    },
    /// Remove a reaction. Patch value: null.
    Remove {
        sender_reaction_id: &'a str,
    },
}

/// Parameters for Message/set update (JMAP Chat §4.5).
///
/// All fields except id are optional; absent fields are not included in the
/// patch. For deletion use deleted_at (and optionally deleted_for_all).
/// Body edits are author-only (server enforces). readAt is a read-receipt update.
#[derive(Debug)]
pub struct MessageUpdateInput<'a> {
    /// Message.id to update.
    pub id: &'a str,
    /// New message body text (author-only edit).
    pub body: Option<&'a str>,
    /// MIME type for body ("text/plain" or "text/markdown").
    pub body_type: Option<&'a str>,
    /// Reaction changes to apply in this update.
    pub reaction_changes: &'a [ReactionChange<'a>],
    /// Set read-receipt timestamp (Message.readAt).
    pub read_at: Option<&'a crate::jmap::UTCDate>,
    /// Soft/hard delete: set to the deletion timestamp.
    pub deleted_at: Option<&'a crate::jmap::UTCDate>,
    /// When Some(true) and deleted_at is also set, deletes for all participants.
    pub deleted_for_all: Option<bool>,
}

Step 2 — Implement message_set_update in crates/jmap-chat/src/methods/message.rs:

pub async fn message_set_update(
    &self,
    session: &crate::jmap::Session,
    input: &MessageUpdateInput<'_>,
) -> Result<SetResponse, crate::error::ClientError> {
    let (api_url, account_id) = Self::session_parts(session)?;
    let mut patch = serde_json::Map::new();
    if let Some(b) = input.body { patch.insert("body".into(), b.into()); }
    if let Some(bt) = input.body_type { patch.insert("bodyType".into(), bt.into()); }
    if let Some(ra) = input.read_at { patch.insert("readAt".into(), ra.as_str().into()); }
    if let Some(da) = input.deleted_at { patch.insert("deletedAt".into(), da.as_str().into()); }
    if let Some(dfa) = input.deleted_for_all { patch.insert("deletedForAll".into(), dfa.into()); }
    for change in input.reaction_changes {
        match change {
            ReactionChange::Add { sender_reaction_id, emoji, sent_at } => {
                patch.insert(
                    format!("reactions/{sender_reaction_id}"),
                    serde_json::json!({"emoji": emoji, "sentAt": sent_at.as_str()}),
                );
            }
            ReactionChange::Remove { sender_reaction_id } => {
                patch.insert(
                    format!("reactions/{sender_reaction_id}"),
                    serde_json::Value::Null,
                );
            }
        }
    }
    let args = serde_json::json!({
        "accountId": account_id,
        "update": { input.id: serde_json::Value::Object(patch) },
    });
    let (call_id, req) = super::build_request("Message/set", args);
    let resp = self.call(api_url, &req).await?;
    crate::client::extract_response(resp, call_id)
}

Step 3 — Implement message_set_destroy in crates/jmap-chat/src/methods/message.rs:

pub async fn message_set_destroy(
    &self,
    session: &crate::jmap::Session,
    ids: &[&str],
) -> Result<SetResponse, crate::error::ClientError> {
    if ids.is_empty() {
        return Err(crate::error::ClientError::InvalidArgument(
            "message_set_destroy: ids may not be empty".into(),
        ));
    }
    let (api_url, account_id) = Self::session_parts(session)?;
    let args = serde_json::json!({
        "accountId": account_id,
        "destroy": ids,
    });
    let (call_id, req) = super::build_request("Message/set", args);
    let resp = self.call(api_url, &req).await?;
    crate::client::extract_response(resp, call_id)
}

Step 4 — Update the import in message.rs:
Add MessageUpdateInput and ReactionChange to the use super::{ ... } import.

Step 5 — Run cargo check to verify compilation.

Defensive rules: No unwrap(). Never log credentials. Empty ids is guarded. Absent patch fields are omitted (not null). senderReactionId keys use format!() not string concat. Type is non_exhaustive not needed here since ReactionChange is an internal pattern.
